import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Karpathy Sequoia 演講：LLM 真正價值、鋸齒狀智能與 Software 3.0 — @AYi_AInotes","description":"","frontmatter":{"title":"Karpathy Sequoia 演講：LLM 真正價值、鋸齒狀智能與 Software 3.0 — @AYi_AInotes","author":"阿绎 AYi（@AYi_AInotes）","date":"2026-05-01T00:00:00.000Z","source":"https://x.com/AYi_AInotes/status/2050058762489036861","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-01-@AYi_AInotes-036861.md","filePath":"research/tweets/2026-05-01-@AYi_AInotes-036861.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-01-@AYi_AInotes-036861.md"};function i(n,t,d,l,h,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="karpathy-sequoia-演講-llm-真正價值、鋸齒狀智能與-software-3-0-—-ayi-ainotes" tabindex="-1">Karpathy Sequoia 演講：LLM 真正價值、鋸齒狀智能與 Software 3.0 — @AYi_AInotes <a class="header-anchor" href="#karpathy-sequoia-演講-llm-真正價值、鋸齒狀智能與-software-3-0-—-ayi-ainotes" aria-label="Permalink to &quot;Karpathy Sequoia 演講：LLM 真正價值、鋸齒狀智能與 Software 3.0 — @AYi_AInotes&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/AYi_AInotes/status/2050058762489036861" target="_blank" rel="noreferrer">https://x.com/AYi_AInotes/status/2050058762489036861</a><strong>作者</strong>：阿绎 AYi（@AYi_AInotes） <strong>發布日期</strong>：2026-05-01 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文 <strong>統計</strong>：227 likes · 52 retweets · 285 bookmarks · 53519 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Karpathy的最新演讲，把我对AI的认知彻底刷新了一遍，</p><p>他说所有人都搞错了LLM的真正价值， 它根本不是用来加速你现有工作的， 核心价值是用来创造那些以前根本不可能存在的东西，</p><p>最震撼的是那个叫menugen的App，就是你输入一张图片然后输出一张图片， 没有一行传统代码， 整个产品就是LLM原生的， 感觉以前的软件1.0和2.0被彻底绕过去了，</p><p>以后我们写的可能都不是.sh脚本，应该是.md技能文件，你用自然语言描述你的意图， LLM会自己适配你的环境，自己调试，自己处理边界情况，</p><p>然后他还提出了一个我见过最准确的LLM心智模型，叫做锯齿状智能，就是同一个模型，能完美重构十万行代码，但同时也会让你走路去洗车🚿🚗哈哈哈</p><p>以前大家觉得这是可验证性的问题，但这次他给出了更深层的解释，叫做经济学驱动，就是说所有高价值高可验证的领域，都会被密集投喂数据，被RL焊死在轨道上，</p><p>那么其他领域就是数据稀疏的丛林，模型只能靠泛化硬闯， 所以你会觉得它有时候神有时候蠢，</p><p>其实根本不是智能高低的问题， 本质上是哪里有钱，哪里的能力就被堆得特别高，</p><p>可以想象未来所有的产品和服务， 都会被拆成感知，执行，逻辑三个部分， 并且横跨软件1.0，2.0，3.0三种范式， 这样的话，程序员的角色也彻底变了，他们不再是写代码的人了哈哈，变成了设计代理系统，守护人类品味和判断的人，听起来有没有很酷兄弟们😎😎😎</p><p>最骚的的是他自己说的，作为一个写了三十年代码的程序员， 他现在每天都觉得自己在落后，</p><p>哇靠，当最顶尖的从业者都觉得自己跟不上的时候意味着什么？？</p><p>说明范式真的在剧烈迁移了， 以后真正的护城河， 不是再是你会写多少行代码了， 而是你能不能读懂LLM的锯齿地图， 能不能设计出放大人类品味的agent系统， 敢不敢去做那些以前根本不可能存在的产品。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Karpathy Sequoia 演講的中文高傳播摘要：LLM 核心價值是創造不可能存在的產品，鋸齒狀智能源自 economics，程序員角色轉向 agent 系統設計師。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>LLM 核心價值：創造以前不可能存在的產品，而非加速現有工作</li><li>鋸齒狀智能：本質是 economics 驅動的 RL 訓練分佈，非智能高低問題</li><li>.md 技能文件取代 .sh 腳本：自然語言意圖 → LLM 自適應執行</li><li>產品拆解：感知/執行/邏輯 × Software 1.0/2.0/3.0</li><li>程序員角色：設計代理系統 + 守護人類品味</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>menugen：zero classical code，純 LLM native app</li><li>Karpathy 本人：寫了 30 年程式碼，每天覺得自己在落後</li><li>鋸齒案例：100k 行 codebase 重構（on-rails）vs. 指路去洗車（off-rails）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>為 Karpathy 原文的中文二手詮釋，53K views 說明中文社群傳播力；原始洞見已在 karpathy/2049903821095354523 歸檔</li><li>「守護人類品味」的描述接近 Sequoia 自身的投資敘事，需辨別原文立場與詮釋者立場</li><li>對中文 AI 社群的傳播追蹤有參考價值</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>4/10</td><td>無超越 karpathy 原文的新行動細節</td></tr><tr><td>B. 創新性 (20%)</td><td>3/10</td><td>二手摘要，核心概念源自原文</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>53K views 有傳播數據，但論點無新增證據</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>通俗化描述，非技術深度</td></tr><tr><td>E. 泛化性 (15%)</td><td>6/10</td><td>框架通用但非新框架</td></tr><tr><td><strong>加權總分</strong></td><td><strong>3.9/10</strong></td><td>4×0.3+3×0.2+4×0.2+3×0.15+6×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 3.9，為 Karpathy 原文的中文摘要，核心洞見已在原文歸檔中涵蓋</p>',29)])])}const _=a(s,[["render",i]]);export{u as __pageData,_ as default};
